package com.example.mfaapp.config;

import com.example.mfaapp.security.MfaAuthenticationFilter;
import com.example.mfaapp.security.MfaAuthenticationProvider;
import com.example.mfaapp.security.MfaLoginSuccessHandler;
import com.example.mfaapp.service.CustomUserDetailsService;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.ProviderManager;
import org.springframework.security.authentication.dao.DaoAuthenticationProvider;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

import java.util.Arrays;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    private final CustomUserDetailsService userDetailsService;
    private final MfaLoginSuccessHandler mfaLoginSuccessHandler;
    private final MfaAuthenticationProvider mfaAuthenticationProvider;

    public SecurityConfig(CustomUserDetailsService userDetailsService,
                          MfaLoginSuccessHandler mfaLoginSuccessHandler,
                          MfaAuthenticationProvider mfaAuthenticationProvider) {
        this.userDetailsService = userDetailsService;
        this.mfaLoginSuccessHandler = mfaLoginSuccessHandler;
        this.mfaAuthenticationProvider = mfaAuthenticationProvider;
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    public DaoAuthenticationProvider daoAuthenticationProvider() {
        DaoAuthenticationProvider provider = new DaoAuthenticationProvider();
        provider.setUserDetailsService(userDetailsService);
        provider.setPasswordEncoder(passwordEncoder());
        return provider;
    }

    @Bean
    public AuthenticationManager authenticationManager() {
        return new ProviderManager(Arrays.asList(daoAuthenticationProvider(), mfaAuthenticationProvider));
    }

    @Bean
    public MfaAuthenticationFilter mfaAuthenticationFilter(AuthenticationManager authenticationManager) {
        MfaAuthenticationFilter filter = new MfaAuthenticationFilter("/mfa/verify", authenticationManager);
        filter.setAuthenticationSuccessHandler(mfaLoginSuccessHandler);
        filter.setAuthenticationFailureHandler((request, response, exception) -> {
            request.getSession().setAttribute("mfaError", exception.getMessage());
            response.sendRedirect("/mfa/verify?error");
        });
        return filter;
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/register", "/css/**", "/js/**", "/webjars/**").permitAll()
                .requestMatchers("/mfa/verify", "/mfa/verify/backup").hasRole("PRE_AUTH_MFA")
                .anyRequest().authenticated()
            )
            .formLogin(form -> form
                .loginPage("/login")
                .successHandler(mfaLoginSuccessHandler)
                .permitAll()
            )
            .logout(logout -> logout
                .permitAll()
            )
            .addFilterBefore(mfaAuthenticationFilter(authenticationManager()), UsernamePasswordAuthenticationFilter.class);

        return http.build();
    }
}

