package com.example.mfaapp.controller;

import com.example.mfaapp.model.User;
import com.example.mfaapp.service.BackupCodeService;
import com.example.mfaapp.service.MfaService;
import com.example.mfaapp.service.UserService;
import com.warrenstrange.googleauth.GoogleAuthenticatorQRGenerator;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.mvc.support.RedirectAttributes;

import java.util.List;
import java.util.Optional;

@Controller
public class AuthController {

    private final UserService userService;
    private final MfaService mfaService;
    private final BackupCodeService backupCodeService;

    public AuthController(UserService userService, MfaService mfaService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.mfaService = mfaService;
        this.backupCodeService = backupCodeService;
    }

    @GetMapping("/login")
    public String showLoginPage() {
        return "login";
    }

    @GetMapping("/register")
    public String showRegisterPage(Model model) {
        model.addAttribute("user", new User());
        return "register";
    }

    @PostMapping("/register")
    public String registerUser(User user, RedirectAttributes redirectAttributes) {
        if (userService.findByUsername(user.getUsername()).isPresent()) {
            redirectAttributes.addFlashAttribute("error", "Username already exists.");
            return "redirect:/register";
        }
        userService.registerNewUser(user);
        redirectAttributes.addFlashAttribute("success", "Registration successful! Please login.");
        return "redirect:/login";
    }

    @GetMapping("/mfa/setup")
    public String showMfaSetup(Authentication authentication, Model model) {
        String username = authentication.getName();
        Optional<User> optionalUser = userService.findByUsername(username);

        if (optionalUser.isEmpty()) {
            return "redirect:/login"; // Should not happen if authenticated
        }

        User user = optionalUser.get();
        if (user.isMfaEnabled()) {
            model.addAttribute("message", "MFA is already enabled for your account.");
            return "redirect:/home";
        }

        String secret = mfaService.generateMfaSecret();
        userService.saveMfaSecret(user, secret);

        String qrCodeUrl = GoogleAuthenticatorQRGenerator.get == null ? "" : GoogleAuthenticatorQRGenerator.getQRData("MFAApp", user.getUsername(), secret);

        model.addAttribute("qrCodeUrl", qrCodeUrl);
        model.addAttribute("secret", secret);
        return "mfa_setup";
    }

    @PostMapping("/mfa/setup/verify")
    public String verifyMfaSetup(@RequestParam("code") String code, Authentication authentication, RedirectAttributes redirectAttributes) {
        String username = authentication.getName();
        Optional<User> optionalUser = userService.findByUsername(username);

        if (optionalUser.isEmpty()) {
            redirectAttributes.addFlashAttribute("error", "User not found.");
            return "redirect:/login";
        }

        User user = optionalUser.get();
        if (user.getMfaSecret() == null) {
            redirectAttributes.addFlashAttribute("error", "MFA setup not initiated.");
            return "redirect:/mfa/setup";
        }

        if (mfaService.validateMfaCode(user.getMfaSecret(), Integer.parseInt(code))) {
            userService.enableMfa(user);
            List<String> backupCodes = backupCodeService.generateAndSaveBackupCodes(user);
            redirectAttributes.addFlashAttribute("success", "MFA enabled successfully! Please save your backup codes.");
            redirectAttributes.addFlashAttribute("backupCodes", backupCodes);
            return "redirect:/mfa/backup-codes";
        } else {
            redirectAttributes.addFlashAttribute("error", "Invalid MFA code. Please try again.");
            return "redirect:/mfa/setup";
        }
    }

    @GetMapping("/mfa/backup-codes")
    public String showBackupCodes(Model model) {
        if (!model.containsAttribute("backupCodes")) {
            // If user directly navigates here, or after refresh, don't show codes again
            return "redirect:/home";
        }
        return "backup_codes";
    }

    @GetMapping("/mfa/verify")
    public String showMfaVerify(@RequestParam(value = "error", required = false) String error, Model model, HttpSession session) {
        if (error != null) {
            String mfaError = (String) session.getAttribute("mfaError");
            model.addAttribute("error", mfaError != null ? mfaError : "Invalid MFA code.");
            session.removeAttribute("mfaError");
        }
        return "mfa_verify";
    }

    @PostMapping("/mfa/verify")
    public String verifyMfaCode(@RequestParam("code") String code, HttpServletRequest request, RedirectAttributes redirectAttributes) {
        // This endpoint is handled by MfaAuthenticationFilter
        // If we reach here, it means the filter failed or wasn't triggered correctly.
        // For a robust solution, the filter should handle the entire flow.
        // This is a fallback/demonstration placeholder.
        redirectAttributes.addFlashAttribute("error", "MFA verification failed. Please try again.");
        return "redirect:/mfa/verify?error";
    }

    @GetMapping("/mfa/verify/backup")
    public String showBackupCodeVerify(Model model, HttpSession session, @RequestParam(value = "error", required = false) String error) {
        if (error != null) {
            String mfaError = (String) session.getAttribute("mfaError");
            model.addAttribute("error", mfaError != null ? mfaError : "Invalid backup code.");
            session.removeAttribute("mfaError");
        }
        return "mfa_verify_backup";
    }

    @PostMapping("/mfa/verify/backup")
    public String verifyBackupCode(@RequestParam("backupCode") String backupCode, HttpServletRequest request, RedirectAttributes redirectAttributes) {
        // This endpoint is handled by MfaAuthenticationFilter
        // If we reach here, it means the filter failed or wasn't triggered correctly.
        // For a robust solution, the filter should handle the entire flow.
        // This is a fallback/demonstration placeholder.
        redirectAttributes.addFlashAttribute("error", "Backup code verification failed. Please try again.");
        return "redirect:/mfa/verify/backup?error";
    }

    @GetMapping("/home")
    public String home(Authentication authentication, Model model) {
        model.addAttribute("username", authentication.getName());
        Optional<User> userOptional = userService.findByUsername(authentication.getName());
        userOptional.ifPresent(user -> model.addAttribute("mfaEnabled", user.isMfaEnabled()));
        return "home";
    }
}

